            AppRoutes = """["/chat"]""",
            Tags = """["chat","walkthrough"]""",
            ContentJson = """{"appRoute":"/chat","startButtonLabel":"Start Chat Tour","steps":[{"element":".chat-panel--page","popover":{"title":"The Chat Panel","description":"This is the chat panel, opened full-page at /chat. The same panel also slides out from the right anywhere in the app when you click the chat icon in the header — the header badge shows your total unread count.","side":"left"}},{"element":".chat-panel__channel-list","popover":{"title":"Direct Messages, Channels & Teams","description":"Your conversations live here in collapsible sections: Direct Messages (private 1:1 chats), Channels (shared group/department/broadcast conversations), and Teams (channels grouped under a team). Use the search box to filter, and click any row to open it.","side":"right"}},{"element":".chat-panel__channel-list .action-btn--create","popover":{"title":"Start a DM or Create a Channel","description":"Use New Message to start a 1:1 direct message with a colleague, or New Group to create a channel (give it a name, type, description, and members). Browse Channels lets you discover and join channels that already exist.","side":"right"}},{"element":".chat-panel__channel-list","popover":{"title":"Open a Conversation & Compose","description":"Click a DM or channel to open it. The message box sits at the bottom — type and press Enter to send (messages are single-line and deliver instantly via SignalR). Use the paperclip to attach a file (up to 10 MB) on a channel. The composer is a plain text box; record links and @mentions you see on incoming messages render as clickable chips, but there is no @ picker in the box while typing.","side":"right"}},{"element":".chat-panel--page","popover":{"title":"Pop Chat Out Into a Window","description":"When chat is open as the slide-out panel (not this full /chat page), the panel header shows an Open in window button (open_in_new icon). Click it to pop chat out into its own browser window you can park on a second monitor. The panel then shows a “Chat is open in a separate window” banner and a Focus window button (launch icon), and clicking a conversation in the panel opens it in the popout window. Closing the popout returns chat to the normal slide-out.","side":"left"}},{"element":".chat-panel--page","popover":{"title":"Threads & Announcements","description":"Reply to any message with Reply in thread to keep a side discussion tidy; a “N replies” link reopens that thread. Announcements arrive here in real time and appear in read-only Broadcast channels — but you author them from Admin > Announcements, not from chat. They can be scoped company-wide, to a department, or to teams, and only admins and managers can post to broadcast channels.","side":"left"}},{"element":".chat-panel__channel-list","popover":{"title":"Unread, Mute & Channel Settings","description":"Each row shows an unread badge, and the header icon shows your total; opening a conversation marks it read. Mute a noisy channel from its row to silence notifications without leaving. Open Channel settings (the gear) to rename or edit a channel or leave it — members are Member, Admin, or Owner.","side":"right"}}]}"""
        });
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Chat Field Reference",
