            Tags = """["chat","reference"]""",
            ContentJson = """{"title":"Chat Field Reference","groups":[{"heading":"Conversation Types","items":[{"label":"Direct Message (DM)","value":"A private 1:1 conversation with one colleague. Listed in the Direct Messages section."},{"label":"Group Channel","value":"A shared, multi-person channel you create for a topic. Listed in the Channels section."},{"label":"Team Channel","value":"A channel that belongs to a Team (ChannelType TeamAuto), grouped under the team's heading in the sidebar."},{"label":"Broadcast / Announcement Channel","value":"A read-only channel (ChannelType Broadcast, IsReadOnly) where only admins and managers can post."},{"label":"System Channel","value":"A channel created automatically by the system for built-in purposes."}]},{"heading":"Sidebar Navigation","items":[{"label":"Search (data-testid: channel-list-search)","value":"Filters conversations and channels in real time as you type."},{"label":"Section headers","value":"Direct Messages, Channels, and Teams — each collapsible via the chevron toggle."},{"label":"New Message (icon: add)","value":"In the Direct Messages section header — opens the user picker to start a 1:1 DM."},{"label":"New Group (icon: add)","value":"In the Channels section header — opens the create-channel dialog."},{"label":"Browse Channels","value":"Discovers existing channels you can join (GET /chat/channels/discover)."},{"label":"Conversation / channel row","value":"Shows avatar/icon, name, last-message preview, timestamp, and unread badge. Click to open."},{"label":"Unread badge / mute icon","value":"Per-row unread count; a notifications_off icon marks a muted channel."}]},{"heading":"Buttons & Actions","items":[{"label":"Open Chat (header icon)","value":"Toggles the slide-out chat panel from any page and shows the total unread badge."},{"label":"Open in window (icon: open_in_new)","value":"In the slide-out panel header — pops chat out into its own browser window (route /chat/popout). Shown only when a popout is not already open. Not shown on the full /chat page."},{"label":"Focus window (icon: launch)","value":"Replaces the Open-in-window button while a popout is open — brings the existing popout window to the front. Also appears on the popout banner."},{"label":"Close (icon: close)","value":"Closes the chat panel and returns to the underlying page."},{"label":"New Message (icon: add)","value":"Opens the user picker to start a 1:1 direct message."},{"label":"New Group / Channel (icon: add)","value":"Opens the create-channel dialog (name, type, description, members)."},{"label":"Browse Channels","value":"Opens the channel browser to find and join existing channels."},{"label":"Channel settings (icon: settings, aria-label: Channel settings)","value":"Opens the channel-settings dialog to rename/edit, view members and roles, or leave."},{"label":"Reply in thread (icon: reply)","value":"On any message — opens the thread panel and posts a reply to that message."},{"label":"Send (icon: send, data-testid: chat-send-btn)","value":"Sends the composed message. Disabled when the input is empty/whitespace (and no file) or while uploading."},{"label":"Attach file (paperclip)","value":"Uploads a file (≤10 MB) that sends with your next message."},{"label":"Mute / Unmute, Leave channel","value":"Mute silences a channel's notifications from its row; Leave (in channel settings) removes you from the channel."}]},{"heading":"Composer & Keyboard","items":[{"label":"Message input (data-testid: chat-message-input)","value":"Single-line text input bound to messageControl. Content is trimmed before sending."},{"label":"Enter","value":"Sends the current message (when non-empty)."},{"label":"Single-line input","value":"Messages are single-line — there is no Shift+Enter newline; Enter always sends."},{"label":"@ in the composer","value":"No @ picker is wired into the live message box — typing @ inserts a literal @ character. (Mentions/record links can exist on messages, but the composer does not author them today.)"},{"label":"Attach file","value":"Paperclip button (channels); accepts PDF, images, office docs, and STEP/STL/DXF up to 10 MB."},{"label":"Send disabled","value":"When the input is empty or whitespace-only (and no file is pending), or while a file is uploading."}]},{"heading":"Threads","items":[{"label":"Reply in thread (icon: reply)","value":"Opens the thread panel for a message and posts replies there (POST /chat/messages/{messageId}/reply)."},{"label":"“N replies” link (icon: forum)","value":"Shown on any message with replies; click to reopen its thread."},{"label":"Thread panel","value":"Side panel showing the parent message, a 'N replies' divider, and all replies with their own composer."}]},{"heading":"Mentions & Record Links (display)","items":[{"label":"User mention","value":"A reference to a teammate that renders as a mention chip on a message. (Mentions are not authored from the live composer today.)"},{"label":"Record link","value":"A link to a record — job, part, purchase order, sales order, quote, etc. — carried on a message and rendered inline."},{"label":"Mention chip","value":"Renders (via the mentionRender pipe) as a clickable colored chip that opens the linked record's detail dialog."}]},{"heading":"Pop-Out Window","items":[{"label":"Open in window","value":"Header button (open_in_new) in the slide-out panel — opens chat in its own window at /chat/popout. Hidden on the full /chat page."},{"label":"Popout banner","value":"Shown in the slide-out while a popout is open: 'Chat is open in a separate window' with a Focus window action."},{"label":"Focus window (launch)","value":"Brings the existing popout window to the front; one popout window exists at a time."},{"label":"Routing while popped out","value":"With a popout open, clicking a DM or channel in the slide-out opens it inside the popout window instead of the panel."},{"label":"Closing","value":"Closing the popout window (or via beforeunload) returns chat to normal slide-out behavior; the banner and Focus button disappear."},{"label":"Window features","value":"Opens at 800x600 named 'qb-chat'; cross-tab/window sync via the 'qb-chat-sync' BroadcastChannel."}]},{"heading":"Announcements","items":[{"label":"Where authored","value":"From Admin > Announcements (the admin Announcements panel) — not from the chat panel. Chat is where announcements are received and read."},{"label":"Who can post","value":"Admins and Managers only (announcements and broadcast channels are read-only to everyone else)."},{"label":"Scope","value":"Company-wide, a specific department, or specific teams (targetTeamIds)."},{"label":"Severity","value":"Info, Warning, or Critical."},{"label":"Acknowledgment","value":"Some announcements require the reader to acknowledge (POST /announcements/{id}/acknowledge)."},{"label":"Templates & expiry","value":"Reusable templates (admin) speed creation; announcements can carry an expiry date."}]},{"heading":"Channel Roles","items":[{"label":"Member","value":"Can read and post in the channel and mute their own notifications."},{"label":"Admin","value":"Can edit the channel (name, description, icon) and manage it."},{"label":"Owner","value":"Full control, including deleting the channel."}]},{"heading":"Timestamps & Date Separators","items":[{"label":"Relative time","value":"'just now' under a minute; '5m', '2h', '3d' for recent messages in the list."},{"label":"Full date","value":"MM/dd/yyyy for messages older than a week in the conversation list."},{"label":"Message time","value":"HH:MM shown on each message bubble."},{"label":"Date separators","value":"'Today', 'Yesterday', or the full date (MM/dd/yyyy) between message groups."}]},{"heading":"Unread & Read-State","items":[{"label":"Header chat icon badge","value":"Total unread across all DMs and channels; updates in real time via SignalR."},{"label":"Per-row badge","value":"Per-DM and per-channel unread count, cleared when the conversation is opened."},{"label":"Mark as read","value":"Opening a conversation marks it read (POST /chat/messages/{otherUserId}/read or /chat/channels/{channelId}/read)."},{"label":"Mute","value":"Silences a channel's notifications (POST /chat/channels/{channelId}/mute) without leaving it."}]},{"heading":"API & Real-Time","items":[{"label":"GET /api/v1/chat/conversations","value":"Lists DM conversations with last-message preview and unread count."},{"label":"GET /api/v1/chat/messages/{otherUserId}","value":"Loads the 1:1 message history with a user (paged)."},{"label":"POST /api/v1/chat/messages","value":"Sends a DM. Body: recipientId, content, optional fileAttachmentId / linkedEntityType / linkedEntityId."},{"label":"POST /api/v1/chat/messages/{otherUserId}/read","value":"Marks all messages from a user as read."},{"label":"GET / POST /api/v1/chat/channels","value":"Lists channels / creates a channel (name, channelType, description, iconName, memberIds)."},{"label":"GET /api/v1/chat/channels/discover","value":"Finds joinable channels (optional ?search=)."},{"label":"POST /api/v1/chat/channels/{channelId}/join | leave | mute | read","value":"Join, leave, mute, or mark-read a channel; /upload attaches a file."},{"label":"GET /api/v1/chat/messages/{messageId}/thread, POST .../reply","value":"Loads a thread / posts a threaded reply."},{"label":"GET / POST /api/v1/announcements","value":"Lists active announcements / creates one (Admin/Manager); /{id}/acknowledge, /templates."},{"label":"SignalR ChatHub (/hubs/chat)","value":"Real-time delivery: messageReceived, roomMessageReceived, announcementReceived. Auto-reconnects with exponential backoff."}]}]}"""
        });
        await GetOrCreateModule(new TrainingModule
