            Summary = "Test your knowledge of the chat system: direct messages vs channels, teams, creating and browsing channels, the composer, threads, mentions, announcements, channel roles, mute, and real-time delivery.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 6,
            IsPublished = true,
