            AppRoutes = """["/chat"]""",
            Tags = """["chat","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"chat1","text":"How do you open the chat panel from any page in the app?","options":[{"id":"a","text":"Navigate to /chat in the sidebar only"},{"id":"b","text":"Click the chat icon in the header bar (it also shows your total unread count)","isCorrect":true},{"id":"c","text":"Press Ctrl+C to toggle chat"},{"id":"d","text":"Open the notification panel and switch to the Messages tab"}],"explanation":"The chat icon in the header toggles the slide-out chat panel from any page and shows your total unread badge. You can also open chat full-page at /chat."},{"id":"chat2","text":"What is the difference between a Direct Message and a Channel?","options":[{"id":"a","text":"A Direct Message is a private 1:1 conversation; a Channel is a shared, multi-person conversation (and may be grouped under a Team)","isCorrect":true},{"id":"b","text":"A Channel can only hold two people; a Direct Message can hold many"},{"id":"c","text":"Direct Messages are real-time but Channels require a page refresh"},{"id":"d","text":"There is no difference — they are two names for the same thing"}],"explanation":"A DM is a private 1:1 conversation in the Direct Messages section. A Channel is a shared conversation in the Channels section that can include many members and may belong to a Team."},{"id":"chat3","text":"You want to create a new shared channel for a project team. What do you do?","options":[{"id":"a","text":"Send a DM to everyone individually"},{"id":"b","text":"Click New Group and fill in the channel name, type, description, and members","isCorrect":true},{"id":"c","text":"Go to Admin > Users and create a group there"},{"id":"d","text":"Post an announcement and ask people to reply"}],"explanation":"New Group opens the create-channel dialog where you set the name, channel type, description, and initial members. The channel then appears in the Channels section."},{"id":"chat4","text":"There is an existing channel you are not a member of. How do you find and join it?","options":[{"id":"a","text":"Click Browse Channels to discover existing channels and join one","isCorrect":true},{"id":"b","text":"You cannot join a channel — an admin must add you"},{"id":"c","text":"Search for it in the global search bar at the top of the app"},{"id":"d","text":"Create a new channel with the same name"}],"explanation":"Browse Channels opens the channel browser (backed by /chat/channels/discover) where you can find channels you are not in and join them."},{"id":"chat5","text":"How do you send a message you have typed in the composer?","options":[{"id":"a","text":"Press Enter — the message sends instantly via SignalR","isCorrect":true},{"id":"b","text":"Press Shift+Enter to send"},{"id":"c","text":"Click outside the input box"},{"id":"d","text":"Wait 5 seconds for it to auto-send"}],"explanation":"Press Enter to send. The message input is single-line, so there is no Shift+Enter newline — Enter always sends. Delivery is instant via the SignalR ChatHub."},{"id":"chat6","text":"You want to reply to one message without cluttering the main conversation. What do you use?","options":[{"id":"a","text":"Reply in thread — it opens the thread panel and keeps the side discussion together","isCorrect":true},{"id":"b","text":"Start a new DM with everyone in the channel"},{"id":"c","text":"Edit the original message to add your reply"},{"id":"d","text":"Quote the message in a new channel"}],"explanation":"Reply in thread opens the thread panel for that message. A message with replies shows a 'N replies' link that reopens the thread, keeping side discussions out of the main flow."},{"id":"chat7","text":"A chat message contains a link to a job. What happens when that record link appears in the conversation?","options":[{"id":"a","text":"It is shown as raw text you must copy and paste into the address bar"},{"id":"b","text":"It renders inline as a clickable chip that opens the job's detail dialog","isCorrect":true},{"id":"c","text":"It downloads the job as a file"},{"id":"d","text":"Nothing — record links are not supported anywhere in chat"}],"explanation":"Record links (job, part, PO, sales order, quote, and more) render inline as clickable colored chips that open the record's detail dialog. Note: the live message composer is a plain text box — typing @ does not open a mention/record picker today, so these links arrive on messages from elsewhere in the system."},{"id":"chat8","text":"Who can post messages in a read-only Broadcast (announcement) channel?","options":[{"id":"a","text":"Anyone who is a member of the channel"},{"id":"b","text":"Only Admins and Managers","isCorrect":true},{"id":"c","text":"Only the person who created the channel"},{"id":"d","text":"No one — broadcast channels are archives"}],"explanation":"Broadcast channels are read-only: only Admins and Managers can post to them. Everyone else reads the announcements but cannot reply in the channel."},{"id":"chat9","text":"Where does an admin go to author and send a company announcement, and what can they control?","options":[{"id":"a","text":"From the chat composer — they type the announcement directly into a channel message box"},{"id":"b","text":"From Admin > Announcements — controlling scope (company-wide, department, or specific teams), severity, whether acknowledgment is required, and an expiry","isCorrect":true},{"id":"c","text":"Anywhere — any user can post an announcement from any DM"},{"id":"d","text":"From the header notification panel's compose tab"}],"explanation":"Announcements are authored from Admin > Announcements (the admin Announcements panel), not from the chat panel. Chat is where announcements are received and read. From the admin panel an admin/manager sets the scope (company-wide, department, or specific teams), a severity (Info/Warning/Critical), optional required acknowledgment, an optional expiry, and can reuse templates."},{"id":"chat10","text":"A channel is very active and the notifications are distracting, but you still need to be a member. What do you do?","options":[{"id":"a","text":"Leave the channel"},{"id":"b","text":"Mute the channel from its row to silence notifications while staying a member","isCorrect":true},{"id":"c","text":"Delete all the messages"},{"id":"d","text":"Block the other members"}],"explanation":"Mute silences a channel's notifications without removing you. The muted channel shows a notifications_off icon; you remain a member and can still read it."},{"id":"chat11","text":"How are messages marked as read, and what does the header badge show?","options":[{"id":"a","text":"You must click 'Mark as read' on each message; the badge shows your online status"},{"id":"b","text":"Opening a conversation marks its messages read; the header badge shows your total unread count across all DMs and channels","isCorrect":true},{"id":"c","text":"Messages are read after 10 seconds; the badge shows the number of channels"},{"id":"d","text":"You must scroll to the bottom; the badge shows how many people are online"}],"explanation":"Opening a DM or channel automatically marks its messages read (via the read endpoints). The header chat icon badge shows your total unread count across every conversation and updates in real time."},{"id":"chat12","text":"What does a channel member's role (Member, Admin, or Owner) determine?","options":[{"id":"a","text":"Nothing — roles are decorative labels"},{"id":"b","text":"Member reads and posts; Admin can edit and manage the channel; Owner has full control including deleting it","isCorrect":true},{"id":"c","text":"The color of the member's avatar"},{"id":"d","text":"How many messages the member can send per day"}],"explanation":"Channel roles govern permissions: a Member can read and post, an Admin can edit and manage the channel (name, description, icon, members), and an Owner has full control including deleting the channel."},{"id":"chat13","text":"You want to keep chat visible on a second monitor while you work in the app. What do you do?","options":[{"id":"a","text":"Open the slide-out chat panel and click Open in window (open_in_new) to pop chat out into its own window","isCorrect":true},{"id":"b","text":"Resize the browser so chat takes the whole screen"},{"id":"c","text":"You cannot — chat must stay inside the app"},{"id":"d","text":"Bookmark /chat and refresh it every few minutes"}],"explanation":"From the slide-out chat panel, the Open in window button (open_in_new) pops chat out into its own window (/chat/popout) you can move to a second monitor. While it is open the panel shows a 'Chat is open in a separate window' banner and a Focus window button, and conversations you click in the panel open in the popout window. Closing the popout returns to the normal slide-out."}]}"""
